import React, { useEffect, useState } from "react";
import Navbar from "../components/Navbar";
import api from "../services/api";

function JournalPage() {
  const [history, setHistory] = useState([]);
  const [dailyCalories, setDailyCalories] = useState([]);
  const [energy, setEnergy] = useState([]);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const res1 = await api.get("/nutrition-history");
      const res2 = await api.get("/daily-calories");
      const res3 = await api.get("/energy-balance");

      setHistory(res1.data);
      setDailyCalories(res2.data);
      setEnergy(res3.data);
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div>
      <Navbar />
      <div className="page-container">
        <h2>Nhật kí dinh dưỡng</h2>

        {/* Tổng calo */}
        <h3>Tổng calo theo ngày</h3>
        {dailyCalories.map((item, i) => (
          <p key={i}>
            {item.meal_date}: {item.total_calories} kcal
          </p>
        ))}

        {/* Trạng thái năng lượng */}
        <h3>Trạng thái năng lượng</h3>
        {energy.map((item, i) => (
          <div key={i}>
            <p>Ngày: {item.meal_date}</p>
            <p>Calo: {item.total_calories}</p>
            <p>TDEE: {item.TDEE}</p>
            <p>Chênh lệch: {item.calorie_balance}</p>
            <p>Trạng thái: {item.energy_status}</p>
            <hr />
          </div>
        ))}

        {/* Chi tiết bữa ăn */}
        <h3>Lịch sử ăn uống</h3>
        {history.map((item, i) => (
          <div key={i}>
            <p>
              {item.meal_date} - {item.meal_type} - {item.food_name}
            </p>
            <p>
              {item.quantity_g}g | {item.calories} kcal
            </p>
            <hr />
          </div>
        ))}
      </div>
    </div>
  );
}

export default JournalPage;
